/**
 * API Integration Tests: Health, Render, TTS, Templates
 * Testa os route handlers críticos usando o next/test-server pattern
 * Nota: Estes testes usam mocks mínimos das dependências externas
 * e verificam contratos de API (schemas, status codes, error handling).
 */

import { NextRequest } from 'next/server';

// -------------------------------------------------------
// Helper: cria NextRequest simulado
// -------------------------------------------------------
function createMockRequest(
  url: string,
  options?: { method?: string; body?: Record<string, unknown>; headers?: Record<string, string> }
): NextRequest {
  const fullUrl = `http://localhost:3000${url}`;
  const init: { method: string; headers: Record<string, string>; body?: string } = {
    method: options?.method ?? 'GET',
    headers: {
      'Content-Type': 'application/json',
      ...(options?.headers ?? {}),
    },
  };
  if (options?.body) {
    init.body = JSON.stringify(options.body);
  }
  return new NextRequest(fullUrl, init);
}

// -------------------------------------------------------
// Health API Contract Tests
// -------------------------------------------------------
describe('API Contract: /api/health', () => {
  it('health endpoint module exports GET handler', async () => {
    // Verify the module exists and exports correctly
    const mod = await import('@/app/api/health/route');
    expect(mod.GET).toBeDefined();
    expect(typeof mod.GET).toBe('function');
  });

  it('health GET handler returns valid JSON with required fields', async () => {
    // Mock health check service to avoid external calls
    jest.mock('@/lib/monitoring/health-check', () => ({
      healthCheckService: {
        checkEssential: jest.fn().mockResolvedValue({
          overall: 'healthy',
          timestamp: new Date(),
          services: [
            { name: 'database', status: 'healthy', latencyMs: 5 },
          ],
          uptime: 1000,
        }),
        checkAll: jest.fn().mockResolvedValue({
          overall: 'healthy',
          timestamp: new Date(),
          services: [],
          uptime: 1000,
        }),
      },
    }));

    jest.mock('@/lib/rate-limit', () => ({
      applyRateLimit: jest.fn().mockResolvedValue(null),
      globalRateLimiter: { check: jest.fn().mockReturnValue({ allowed: true, remaining: 99, retryAfterSec: 0, limit: 100 }) },
      checkRateLimit: jest.fn().mockResolvedValue(null),
    }));

    const { GET } = await import('@/app/api/health/route');
    const req = createMockRequest('/api/health');
    const res = await GET(req);

    expect(res.status).toBeLessThan(500);
    
    if (res.status === 200) {
      const body = await res.json();
      expect(body.status).toBeDefined();
      expect(body.timestamp).toBeDefined();
      expect(body.version).toBeDefined();
    }
  });
});

