// -------------------------------------------------------
// Stripe Webhook Contract Tests
// -------------------------------------------------------
describe('API Contract: /api/stripe/webhook', () => {
  it('webhook module exports POST handler', async () => {
    const mod = await import('@/app/api/stripe/webhook/route');
    expect(mod.POST).toBeDefined();
    expect(typeof mod.POST).toBe('function');
  });

  it('POST without signature returns 400 or 503', async () => {
    jest.mock('@/lib/rate-limit', () => ({
      applyRateLimit: jest.fn().mockResolvedValue(null),
      globalRateLimiter: { check: jest.fn().mockReturnValue({ allowed: true, remaining: 99, retryAfterSec: 0, limit: 100 }) },
      checkRateLimit: jest.fn().mockResolvedValue(null),
    }));

    const { POST } = await import('@/app/api/stripe/webhook/route');
    const req = createMockRequest('/api/stripe/webhook', {
      method: 'POST',
      body: { type: 'test.event' },
    });
    
    const res = await POST(req);
    // Without STRIPE_SECRET_KEY or signature, should return 400 or 503
    expect([400, 503]).toContain(res.status);
  });
});
